	s.Lock()
	defer s.Unlock()

	for j, e := range s.BlacklistedJTIs {
		if e.Before(time.Now()) {
			delete(s.BlacklistedJTIs, j)
		}
	}

	if _, exists := s.BlacklistedJTIs[jti]; exists {
		return errors.WithStack(fosite.ErrJTIKnown)
	}

	s.BlacklistedJTIs[jti] = exp
	return nil
}

